grader.tests:
if (JSON.stringify(parseRange('1-3,5,7-9')) !== '[1,2,3,5,7,8,9]') throw new Error("parseRange('1-3,5,7-9') wrong");
if (JSON.stringify(parseRange('4')) !== '[4]') throw new Error("parseRange('4') wrong");
if (JSON.stringify(parseRange(' 1 , 2-2 ')) !== '[1,2]') throw new Error('spaces not ignored');
let threw1 = false; try { parseRange('5-2'); } catch { threw1 = true; } if (!threw1) throw new Error('reversed range must throw');
let threw2 = false; try { parseRange('1,,2'); } catch { threw2 = true; } if (!threw2) throw new Error('empty part must throw');

if (isBalanced('a(b[c]{d})') !== true) throw new Error('nested mix should be true');
if (isBalanced('([)]') !== false) throw new Error('interleaved should be false');
if (isBalanced('') !== true) throw new Error('empty should be true');
if (isBalanced(')(') !== false) throw new Error('close-first should be false');
if (isBalanced('((') !== false) throw new Error('unclosed should be false');

if (luhnValid('79927398713') !== true) throw new Error('79927398713 is valid');
if (luhnValid('79927398714') !== false) throw new Error('79927398714 is invalid');
if (luhnValid('4539148803436467') !== true) throw new Error('4539148803436467 is valid');
if (luhnValid('1234a') !== false) throw new Error('non-digits must be false');
if (luhnValid('') !== false) throw new Error('empty must be false');

if (romanToInt('III') !== 3) throw new Error('III wrong');
if (romanToInt('LVIII') !== 58) throw new Error('LVIII wrong');
if (romanToInt('MCMXCIV') !== 1994) throw new Error('MCMXCIV wrong');
if (romanToInt('IX') !== 9) throw new Error('IX wrong');
